CustomField.formula:
IF(
  spot__c = TRUE,
  0,
  IF(
    NOT(
      OR(
        AND(
          MONTH(TODAY()) >= 7,
          OR(
            AND(
              YEAR(occur_revenu_month__c) = YEAR(TODAY()) + 1,
              MONTH(occur_revenu_month__c) >= 7
            ),
            AND(
              YEAR(occur_revenu_month__c) = YEAR(TODAY()) + 2,
              MONTH(occur_revenu_month__c) <= 6
            )
          )
        ),
        AND(
          MONTH(TODAY()) < 7,
          OR(
            AND(
              YEAR(occur_revenu_month__c) = YEAR(TODAY()),
              MONTH(occur_revenu_month__c) >= 7
            ),
            AND(
              YEAR(occur_revenu_month__c) = YEAR(TODAY()) + 1,
              MONTH(occur_revenu_month__c) <= 6
            )
          )
        )
      )
    ),
    0,
    Estimated_Amount__c / 12 * 0.3 / 0.8 *
    MAX(
      (
        (YEAR(TODAY()) + IF(MONTH(TODAY()) < 7, 1, 2)) * 12 + 6
      ) -
      (
        YEAR(occur_revenu_month__c) * 12 + MONTH(occur_revenu_month__c)
      ) + 1,
      0
    )
  )
)
